---

## Current Issues

The current code is minimal but has several gaps for a production-ready application:

1. **No request body parsing** — `express.json()` / `express.urlencoded()` middleware is missing, making POST/PUT endpoints blind to request bodies.
2. **No input validation** — No sanitization or validation of query parameters or body inputs.
3. **No error handling middleware** — Unhandled errors will leak stack traces or crash the process.
4. **No rate limiting** — Endpoints are open to abuse/DoS.
5. **No security headers** — Missing HTTP security headers (e.g., `X-Content-Type-Options`, `Strict-Transport-Security`).
6. **Static/hardcoded data** — The `/users` endpoint returns hardcoded data; a real endpoint would need query param validation.
7. **No request logging** — Makes debugging and auditing difficult.

---

## Suggested Improvements

```js
const express = require('express');
const app = express();

// --- Security headers (use helmet in production) ---
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  res.setHeader('Referrer-Policy', 'no-referrer');
  next();
});

// --- Body parsing with size limits to prevent payload attacks ---
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// --- Input validation helper ---
function isPositiveInteger(value) {
  const num = Number(value);
  return Number.isInteger(num) && num > 0;
}

// --- Health check ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// --- Users endpoint with query param validation ---
app.get('/users', (req, res, next) => {
  try {
    const { page = '1', limit = '10' } = req.query;

    // Validate pagination params
    if (!isPositiveInteger(page) || !isPositiveInteger(limit)) {
      return res.status(400).json({
        error: 'Invalid parameters',
        message: '`page` and `limit` must be positive integers.',
      });
    }

    const pageNum = Number(page);
    const limitNum = Math.min(Number(limit), 100); // Cap to prevent over-fetching

    const allUsers = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    const start = (pageNum - 1) * limitNum;
    const paginatedUsers = allUsers.slice(start, start + limitNum);

    res.json({ data: paginatedUsers, page: pageNum, limit: limitNum });
  } catch (err) {
    next(err); // Forward to centralized error handler
  }
});

// --- 404 handler for unknown routes ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not Found', message: 'The requested resource does not exist.' });
});

// --- Centralized error handler (must have 4 args) ---
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, next) => {
  console.error(`[${new Date().toISOString()}] ERROR:`, err.message);

  // Don't leak internal error details to clients
  const statusCode = err.status || err.statusCode || 500;
  const message =
    process.env.NODE_ENV === 'production' ? 'An internal error occurred.' : err.message;

  res.status(statusCode).json({ error: 'Internal Server Error', message });
});

// --- Graceful startup ---
const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

// --- Graceful shutdown ---
process.on('SIGTERM', () => {
  console.log('SIGTERM received. Shutting down gracefully...');
  server.close(() => {
    console.log('Server closed.');
    process.exit(0);
  });
});

module.exports = app;
```

