  const allowedOrigin = process.env.ALLOWED_ORIGIN || 'https://yourdomain.com';
  res.setHeader('Access-Control-Allow-Origin', allowedOrigin);
  res.setHeader('Access-Control-Allow-Methods', 'GET');
  next();
